// Encode calldata for an ERC-20 transfer(to, amount) call.

function encodeErc20Transfer(keccak256, to, amount) {
  const sel = keccak256(Buffer.from([[SLOT fn_sig]], 'utf8')).slice(0, 8);

  let addr = to.toLowerCase();
  if (addr.startsWith('0x')) addr = addr.slice(2);
  if (addr.length !== 40 || !/^[0-9a-f]{40}$/.test(addr)) {
    throw new Error('to must be a 20-byte hex address');
  }
  const paddedAddr = [[SLOT addr_pad]];

  const a = BigInt(amount);
  if (a < 0n) throw new Error('amount cannot be negative');
  if (a >= [[SLOT max_amount]]) throw new Error('amount overflow');
  const paddedAmount = a.toString(16).padStart(64, '0');

  return '0x' + sel + paddedAddr + paddedAmount;
}

module.exports = { encodeErc20Transfer };
